ASN1T_Cause::~ASN1T_Cause ()
{
   OSCTXT* pctxt = mpContext.getCtxtPtr();
   if (pctxt != 0 && !rtxMemHeapIsEmpty (pctxt)) {
      asn1Free_Cause (pctxt, this);
   }
}

int ASN1C_Cause::EncodeTo (OSRTMessageBufferIF& msgBuf)
{
   int stat = setMsgBuf (msgBuf, TRUE);
   if (stat != 0) return (stat);

   if (msgBuf.isA (OSRTMessageBufferIF::PEREncode)) {
      stat= asn1PE_Cause (msgBuf.getCtxtPtr(), &msgData);
      ((ASN1PEREncodeBuffer&)msgBuf).byteAlign();
      return stat;
   }
   else if (msgBuf.isA (OSRTMessageBufferIF::JSONEncode)) {
      return asn1JsonEnc_Cause (msgBuf.getCtxtPtr(), &msgData);
   }
   return RTERR_NOTSUPP;
}

int ASN1C_Cause::DecodeFrom (OSRTMessageBufferIF& msgBuf, OSBOOL free)
{
   int stat = setMsgBuf (msgBuf, TRUE);
   if (stat != 0) return (stat);

   asn1Init_Cause (&msgData, free, getCtxtPtr());
   msgData.setContext (msgBuf.getContext());
   if (msgBuf.isA (OSRTMessageBufferIF::PERDecode)) {
      stat = asn1PD_Cause (msgBuf.getCtxtPtr(), &msgData);
      ((ASN1PERDecodeBuffer&)msgBuf).byteAlign();
      return stat;
   }
   else if (msgBuf.isA (OSRTMessageBufferIF::JSONDecode)) {
      return asn1JsonDec_Cause (msgBuf.getCtxtPtr(), &msgData);
   }
   return RTERR_NOTSUPP;
}

int asn1Init_Cause (ASN1T_Cause* pvalue, OSBOOL free, OSCTXT *pctxt)
{
   if (0 == pvalue) return RTERR_NULLPTR;
   if (free) {
      asn1Free_Cause (pctxt, pvalue);
   }
   else {
      pvalue->t = 0;
      OSCRTLMEMSET (&pvalue->u, 0, sizeof(pvalue->u));
   }
   return 0;
}

void asn1Free_Cause (OSCTXT *pctxt, ASN1T_Cause* pvalue)
{
   if (0 == pvalue) return;
   switch (pvalue->t) {
      case 0: break; /* no choice; nothing to free */
      case 1:
         break;

      case 2:
         break;

      case 3:
         break;

      case 4:
         break;

      case 5:
         break;

      case 6:
         break;

      default:
         if (0 != pvalue->u.extElem1) {
            if (!rtxCtxtTestFlag (pctxt, ASN1FASTCOPY)) {
               rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1->data);
               pvalue->u.extElem1->data = 0;
            }
            rtxMemFreePtr (pctxt, (void*)pvalue->u.extElem1);
            pvalue->u.extElem1 = 0;
         }
   }
}

void ASN1C_Cause::MemFree ()
{
   asn1Free_Cause (getCtxtPtr(), &msgData);
}

