/* ASN1T_TypeOfError */

const OSEnumItem ASN1T_TypeOfError_ENUMTAB[] = {
   { OSUTF8("missing"), 1, 7, 1 },
   { OSUTF8("not-understood"), 0, 14, 0 }
} ;

const OSUTF8CHAR* ASN1T_TypeOfError_ToString (OSINT32 value)
{
   OSINT32 idx = value;

   if (idx >= 0 && idx < ASN1T_TypeOfError_ENUMTABSIZE) {
      return ASN1T_TypeOfError_ENUMTAB
         [ASN1T_TypeOfError_ENUMTAB[idx].transidx].name;
   }
   else
      return OSUTF8("_UNKNOWN_");
}

int ASN1T_TypeOfError_ToEnum (OSCTXT* pctxt,
   const OSUTF8CHAR* value, ASN1T_TypeOfError* pvalue)
{
   OSSIZE valueLen = rtxUTF8LenBytes (value);
   return ASN1T_TypeOfError_ToEnum2 (pctxt, value, valueLen, pvalue);
}

int ASN1T_TypeOfError_ToEnum2 (OSCTXT* pctxt,
   const OSUTF8CHAR* value, OSSIZE valueLen, ASN1T_TypeOfError* pvalue)
{
   OSINT32 idx = rtxLookupEnum (value, valueLen, ASN1T_TypeOfError_ENUMTAB, 
      ASN1T_TypeOfError_ENUMTABSIZE);

   if (idx >= 0) {
      *pvalue = (ASN1T_TypeOfError)ASN1T_TypeOfError_ENUMTAB[idx].value;
      return 0;
   }
   else {
      rtxErrAddStrParm (pctxt, (const char*)value);
      return LOG_RTERR (pctxt, RTERR_INVENUM);
   }
}

